# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

// MainActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Patterns
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.IOException

class MainActivity : AppCompatActivity() {

    private lateinit var contentTextView: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        contentTextView = findViewById(R.id.contentTextView)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIncomingIntent(it) }
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleSharedImages(intent)
                }
            }
            else -> {
                displayDefaultContent()
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            val result = processSharedText(sharedText)
            displayContent(result)
        } else {
            showToast("No text content found")
        }
    }

    private fun processSharedText(text: String): String {
        val urls = extractUrls(text)
        return if (urls.isNotEmpty()) {
            buildString {
                append("Shared Text Content:\n\n")
                append("Original Text:\n$text\n\n")
                append("Extracted URLs (${urls.size}):\n")
                urls.forEachIndexed { index, url ->
                    append("${index + 1}. $url\n")
                }
            }
        } else {
            "Shared Text Content:\n\n$text"
        }
    }

    private fun extractUrls(text: String): List<String> {
        val urls = mutableListOf<String>()
        val matcher = Patterns.WEB_URL.matcher(text)
        while (matcher.find()) {
            matcher.group()?.let { urls.add(it) }
        }
        return urls
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            val result = processSharedImage(imageUri)
            displayContent(result)
        } else {
            showToast("No image content found")
        }
    }

    private fun processSharedImage(uri: Uri): String {
        return buildString {
            append("Shared Image Content:\n\n")
            append("Image URI:\n$uri\n\n")
            
            try {
                val mimeType = contentResolver.getType(uri)
                append("MIME Type: ${mimeType ?: "Unknown"}\n\n")
                
                contentResolver.openInputStream(uri)?.use { inputStream ->
                    val size = inputStream.available()
                    append("Size: ${formatFileSize(size)}\n\n")
                }
                
                val cursor = contentResolver.query(uri, null, null, null, null)
                cursor?.use {
                    if (it.moveToFirst()) {
                        append("Additional Info:\n")
                        for (i in 0 until it.columnCount) {
                            val columnName = it.getColumnName(i)
                            val value = it.getString(i)
                            if (value != null) {
                                append("$columnName: $value\n")
                            }
                        }
                    }
                }
            } catch (e: IOException) {
                append("Error reading image: ${e.message}\n")
            } catch (e: SecurityException) {
                append("Permission denied to access image\n")
            }
        }
    }

    private fun handleSharedImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUris != null && imageUris.isNotEmpty()) {
            val result = processSharedImages(imageUris)
            displayContent(result)
        } else {
            showToast("No images found")
        }
    }

    private fun processSharedImages(uris: ArrayList<Uri>): String {
        return buildString {
            append("Shared Multiple Images:\n\n")
            append("Total Images: ${uris.size}\n\n")
            
            uris.forEachIndexed { index, uri ->
                append("Image ${index + 1}:\n")
                append("URI: $uri\n")
                
                try {
                    val mimeType = contentResolver.getType(uri)
                    append("Type: ${mimeType ?: "Unknown"}\n")
                    
                    contentResolver.openInputStream(uri)?.use { inputStream ->
                        val size = inputStream.available()
                        append("Size: ${formatFileSize(size)}\n")
                    }
                } catch (e: Exception) {
                    append("Error: ${e.message}\n")
                }
                
                append("\n")
            }
        }
    }

    private fun formatFileSize(size: Int): String {
        return when {
            size < 1024 -> "$size B"
            size < 1024 * 1024 -> "${size / 1024} KB"
            else -> "${size / (1024 * 1024)} MB"
        }
    }

    private fun displayContent(content: String) {
        contentTextView.text = content
        showToast("Content processed successfully")
    }

    private fun displayDefaultContent() {
        contentTextView.text = "Share Handler App\n\nShare URLs or images from other apps to see them here."
    }

    private fun showToast(message: String) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
    }
}